// Helper: get a random shuffled set of N questions from a specialty
export function getRandomQuestions(specialty, count = 10) {
  const pool = [...(QUESTION_BANK[specialty] || [])];
  // Fisher-Yates shuffle
  for (let i = pool.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [pool[i], pool[j]] = [pool[j], pool[i]];
  }
  return pool.slice(0, Math.min(count, pool.length));
}

export const SPECIALTIES = Object.keys(QUESTION_BANK);
